import click
import yaml
import json
import csv
from pathlib import Path
from app.config import load_config, ConfigError

@click.command()
@click.option('--format', type=click.Choice(['json', 'csv']), default='json', help='Export format.')
@click.option('--output', type=click.Path(), help='Output file path.')
@click.option('--verbose', is_flag=True, help='Enable verbose output.')
@click.pass_context
def export(ctx, format, output, verbose):
    """Export projects in JSON or CSV format."""
    try:
        config = load_config()
        projects = config['projects']
        if not projects:
            click.echo("No projects to export.")
            ctx.exit(1)

        if not output:
            output = f"projects.{format}"

        if format == 'json':
            export_json(projects, output, verbose)
        elif format == 'csv':
            export_csv(projects, output, verbose)
    except ConfigError as e:
        click.echo(f"Error loading configuration: {e}")
        ctx.exit(1)
    except Exception as e:
        click.echo(f"An unexpected error occurred: {e}")
        ctx.exit(1)
```

