    try:
        db = SessionLocal()
        db.execute("SELECT 1")
        db.close()
        return {"status": "ok", "database": "connected"}
    except OperationalError:
        return {"status": "error", "database": "disconnected"}

def check_remote_service_health(url):
    try:
        response = requests.get(url, timeout=5)
        if response.status_code == 200:
            return {"status": "ok", "service": url}
        else:
            return {"status": "error", "service": url, "response_code": response.status_code}
    except requests.RequestException as e:
        return {"status": "error", "service": url, "error": str(e)}

def run_health_checks():
    health_checks = {
        "database": check_database_health(),
        "remote_services": [],
    }

    for url in REMOTE_SERVICE_URLS:
        health_checks["remote_services"].append(check_remote_service_health(url))

    return health_checks
```

