                    validate(instance=plugin_config, schema=config_schema['properties']['plugins']['patternProperties']['^.*$'])
                    config_data.setdefault(plugin_dir, {}).update(plugin_config)

        validate(instance=config_data, schema=config_schema)
        return config_data

