            try:
                connector.connect()

                # For webhooks, the connect method starts the listener
                continue

            except Exception as e:
                logger.error(f"Failed to start webhook listener: {e}")

        # Optionally wait for webhook listener to finish processing
        if self.connectors and isinstance(self.connectors[-1], WebhookListenerConnector):
            try:
                # Implement graceful shutdown logic here
                pass
            finally:
                connector.disconnect()

        logger.info("ETL process completed")

def handle_webhook_retry(webhook_config, retries=3):
    attempts = 0
    while attempts < retries:
        try:
            webhook_listener = EventWebhookListener(webhook_config)
            webhook_listener.connect()

            # Wait for the listener to start and then return
            time.sleep(1)  # Give some buffer time before returning

            return webhook_listener
        except Exception as e:
