import json

def load_metadata(file_path):
    """Loads metadata from a JSON file."""
    with open(file_path) as f:
        return json.load(f)

def compare_row_counts(metadata1, metadata2):
    """Compares row counts between two consecutive runs for each stage."""
    stages = ["extract", "transform", "load"]

    for stage in stages:
        if stage not in metadata1['records_processed'] or stage not in metadata2['records_processed']:
            raise ValueError(f"Metadata does not contain records processed information for {stage}.")

        row_count_run_1 = metadata1['records_processed'][stage]
        row_count_run_2 = metadata2['records_processed'][stage]

        difference = row_count_run_2 - row_count_run_1
        if difference > 0:
            print(f"Row count increased by {difference} rows from run {metadata1['run_id']} to run {metadata2['run_id']} in stage {stage}")
        elif difference < 0:
            print(f"Row count decreased by {-difference} rows from run {metadata1['run_id']} to run {metadata2['run_id']} in stage {stage}")
        else:
            print(f"No change in row count between runs for stage {stage}")

