import os
from glob import glob
import polars as pl

class BaseConnector:
    def __init__(self, config):
        self.config = config

    def connect(self):
        """Establishes the connection to the data source."""
        raise NotImplementedError("This method should be overridden by subclasses.")

    def fetch_data(self) -> pl.DataFrame:
        """Fetches data from the connected source and returns it as a Polars DataFrame."""
        raise NotImplementedError("This method should be overridden by subclasses.")

class CSVDirectoryConnector(BaseConnector):
    def connect(self):
        self.file_paths = glob(os.path.join(self.config.directory, '*.csv'))

    def fetch_data(self) -> pl.DataFrame:
        dfs = [pl.read_csv(file_path) for file_path in self.file_paths]

        return pl.concat(dfs, how="vertical") if dfs else None

class JSONDirectoryConnector(BaseConnector):
    def connect(self):
        self.file_paths = glob(os.path.join(self.config.directory, '*.json'))

    def fetch_data(self) -> pl.DataFrame:
        dfs = []

        for file_path in self.file_paths:
            with open(file_path, 'r') as f:
                data = json.load(f)

            # Convert JSON to DataFrame
            df = pl.DataFrame(data)

            dfs.append(df)

        return pl.concat(dfs) if dfs else None

class RESTAPICConnector(BaseConnector):
    def connect(self):
        pass  # REST APIs don't require explicit connection

    def fetch_data(self) -> pl.DataFrame:
        response = requests.get(self.config.url, headers=self.config.headers)

        if response.status_code == 200:
            data = response.json()

            # Convert JSON to DataFrame
            df = pl.DataFrame(data)

            return df
        else:
            raise Exception(f"Failed to fetch data from {self.config.url}")

class SchemaManager:
    def __init__(self, initial_schema):
        self.current_schema = set(initial_schema)

    def update_schema(self, new_columns):
        # Add new columns to the current schema if they don't exist already.
        for column in new_columns:
            if column not in self.current_schema:
                self.current_schema.add(column)

    def get_current_schema(self):
        return list(self.current_schema)

class DataTransformer:
    def __init__(self, schema_manager: SchemaManager):
        self.schema_manager = schema_manager

    def transform(self, df: pl.DataFrame) -> pl.DataFrame:
        # Example transformation: Convert all column names to lowercase and remove duplicates.

        # Ensure columns are in lowercase
        df = df.to_df().select(pl.col("*").str_lower())

        return df.unique()

    def save_as_parquet(self, df: pl.DataFrame, output_path):
        Path(output_path).parent.mkdir(parents=True, exist_ok=True)
        df.write_parquet(output_path)

class DataLoader:
    def __init__(self, db_path):
        self.conn = sqlite3.connect(db_path)

    def load(self, parquet_file: str):
        # Load the Parquet file into a Polars DataFrame
        df = pl.read_parquet(parquet_file)

        # Convert DataFrame to pandas for compatibility with SQLite (if needed)
        pd_df = df.to_pandas()

        pd_df.to_sql('data_table', con=self.conn, if_exists='replace')

class ETLOrchestrator:
    def __init__(self, csv_directory=None, api_url=None):
        self.connectors = []

        if csv_directory:
            self.connectors.append(CSVDirectoryConnector(CSVDirectoryConfig(directory=csv_directory)))

        if api_url:
            self.connectors.append(RESTAPICConnector(RESTAPICConfig(url=api_url)))

    def run(self):
        logger.info("ETL process started")

        data_sources = []

        for connector in self.connectors:
            try:
                connector.connect()
                data_sources.append((connector.__class__.__name__, connector.fetch_data()))
            except Exception as e:
                logger.error(f"Failed to fetch data from {connector.__class__.__name__}: {e}")

        transformer = DataTransformer(SchemaManager(initial_schema=['column1', 'column2']))

        transformed_data_paths = []
        for source, data in data_sources:
            try:
                output_path = f'/path/to/silver_layer_{source}.parquet'
                transformer.save_as_parquet(data, output_path)
                transformed_data_paths.append(output_path)
            except Exception as e:
                logger.error(f"Transformation failed for {source}: {e}")

        loader = DataLoader(db_path='data.db')

        try:
            for parquet_file in transformed_data_paths:
                loader.load(parquet_file)
        except Exception as e:
            logger.error(f"Loading data to database failed: {e}")

        logger.info("ETL process completed")
