```python
import click
import os
import yaml
import json
import csv
import logging

from .. import config

def configure_logging(verbose):
    logging.basicConfig(level=logging.DEBUG if verbose else logging.INFO)
    logging.getLogger('werkzeug').setLevel(logging.ERROR)

@click.command()
@click.option('--format', type=click.Choice(['json', 'yaml', 'csv']), default='json', help='Output format (json, yaml, or csv)')
@click.option('--output', type=click.Path(), help='Output file path')
@click.option('--verbose', is_flag=True, help='Enable verbose output')
def export(format, output, verbose):
    configure_logging(verbose)

    config_data = config.load_config()

    try:
        if format == 'json':
            data = json.dumps(config_data, indent=4)
            if output:
                with open(output, 'w') as file:
                    file.write(data)
            else:
                click.echo(data)
        elif format == 'yaml':
            data = yaml.dump(config_data)
            if output:
                with open(output, 'w') as file:
                    file.write(data)
            else:
                click.echo(data)
        elif format == 'csv':
            if not output:
                raise ValueError("CSV export requires an output file path")

            with open(output, 'w', newline='') as file:
                writer = csv.writer(file)
                writer.writerow(['Section', 'Key', 'Value'])
                for section, section_data in config_data.items():
                    for key, value in section_data.items():
                        writer.writerow([section, key, value])

        logging.info(f'Successfully exported configuration in {format} format')
        return 0
    except Exception as e:
        logging.error(f'Failed to export configuration: {e}')
        return 1
```

